class Solution:
    def frequencySort(self, s: str) -> str:
        cnt = Counter(s)
        buckets = [[] for _ in range(len(s)+1)]
        for ch, f in cnt.items(): buckets[f].append(ch)
        ans = []
        for f in range(len(s), 0, -1):
            for ch in buckets[f]: ans.append(ch * f)
        return "".join(ans)

