class Solution {
public:
    string frequencySort(string s) {
        int cnt[128]={};
        for(char c:s) cnt[c]++;
        vector<string> b(s.size()+1);
        for(int i=0;i<128;i++) if(cnt[i]) b[cnt[i]]+=char(i);
        string ans;
        for(int f=s.size();f;f--) for(char c:b[f]) ans+=string(cnt[c],c);
        return ans;
    }
};

